#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>

#include "backprop.h"

////////////////////////////////////////////////////////////////////////////////

extern void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2);

extern void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err);

extern void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err);

extern void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw);


extern int setup(int argc, char** argv);

extern float **alloc_2d_dbl(int m, int n);

extern float squash(float x);

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

////////////////////////////////////////////////////////////////////////////////
// Program main
////////////////////////////////////////////////////////////////////////////////
int
main( int argc, char** argv)
{
	setup(argc, argv);
}

__global__ void bpnn_layerforward_kernel(float *l1, float *l2, float **conn, int n1, int n2) {
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    if (j < n2) {
        float sum = 0.0f;
        for (int k = 0; k <= n1; k++) {
            sum += conn[k][j+1] * l1[k];
        }
        l2[j+1] = squash(sum);
    }
}

__global__ void bpnn_output_error_kernel(float *delta, float *target, float *output, int nj, float *err) {
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    if (j < nj) {
        float o = output[j+1];
        float t = target[j+1];
        delta[j+1] = o * (1.0f - o) * (t - o);
    }
    if (j == 0) {
        float errsum = 0.0f;
        for (int i = 1; i <= nj; i++) {
            errsum += fabsf(delta[i]);
        }
        err[0] = errsum;
    }
}

__global__ void bpnn_hidden_error_kernel(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err) {
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    if (j < nh) {
        float h = hidden[j+1];
        float sum = 0.0f;
        for (int k = 1; k <= no; k++) {
            sum += delta_o[k] * who[j+1][k];
        }
        delta_h[j+1] = h * (1.0f - h) * sum;
    }
    if (j == 0) {
        float errsum = 0.0f;
        for (int i = 1; i <= nh; i++) {
            errsum += fabsf(delta_h[i]);
        }
        err[0] = errsum;
    }
}

__global__ void bpnn_adjust_weights_kernel(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw) {
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    if (j < ndelta) {
        for (int k = 0; k <= nly; k++) {
            float new_dw = ((ETA * delta[j+1] * ly[k]) + (MOMENTUM * oldw[k][j+1]));
            w[k][j+1] += new_dw;
            oldw[k][j+1] = new_dw;
        }
    }
}

void bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
  int in, hid, out;
  float out_err, hid_err;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  // Allocate memory on the device
  float *d_input_units, *d_hidden_units, *d_output_units;
  float *d_hidden_delta, *d_output_delta, *d_target;
  float **d_input_weights_ptr, **d_hidden_weights_ptr;
  float **d_input_prev_weights_ptr, **d_hidden_prev_weights_ptr;

  cudaMalloc(&d_input_units, (in + 1) * sizeof(float));
  cudaMalloc(&d_hidden_units, (hid + 1) * sizeof(float));
  cudaMalloc(&d_output_units, (out + 1) * sizeof(float));
  cudaMalloc(&d_hidden_delta, (hid + 1) * sizeof(float));
  cudaMalloc(&d_output_delta, (out + 1) * sizeof(float));
  cudaMalloc(&d_target, (out + 1) * sizeof(float));

  cudaMalloc(&d_input_weights_ptr, (in + 1) * sizeof(float*));
  cudaMalloc(&d_hidden_weights_ptr, (hid + 1) * sizeof(float*));
  cudaMalloc(&d_input_prev_weights_ptr, (in + 1) * sizeof(float*));
  cudaMalloc(&d_hidden_prev_weights_ptr, (hid + 1) * sizeof(float*));

  // Copy weights and units from host to device
  cudaMemcpy(d_input_units, net->input_units, (in + 1) * sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(d_hidden_units, net->hidden_units, (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(d_output_units, net->output_units, (out + 1) * sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(d_target, net->target, (out + 1) * sizeof(float), cudaMemcpyHostToDevice);

  // Allocate and copy input weights
  float **d_input_weights_data;
  cudaMalloc(&d_input_weights_data, (in + 1) * (hid + 1) * sizeof(float));
  for (int i = 0; i <= in; i++) {
      d_input_weights_ptr[i] = (float*)((char*)d_input_weights_data + i * (hid + 1) * sizeof(float));
      cudaMemcpy(d_input_weights_ptr[i], net->input_weights[i], (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
  }

  // Allocate and copy hidden weights
  float **d_hidden_weights_data;
  cudaMalloc(&d_hidden_weights_data, (hid + 1) * (out + 1) * sizeof(float));
  for (int i = 0; i <= hid; i++) {
      d_hidden_weights_ptr[i] = (float*)((char*)d_hidden_weights_data + i * (out + 1) * sizeof(float));
      cudaMemcpy(d_hidden_weights_ptr[i], net->hidden_weights[i], (out + 1) * sizeof(float), cudaMemcpyHostToDevice);
  }

  // Allocate and copy input prev weights
  float **d_input_prev_weights_data;
  cudaMalloc(&d_input_prev_weights_data, (in + 1) * (hid + 1) * sizeof(float));
  for (int i = 0; i <= in; i++) {
      d_input_prev_weights_ptr[i] = (float*)((char*)d_input_prev_weights_data + i * (hid + 1) * sizeof(float));
      cudaMemcpy(d_input_prev_weights_ptr[i], net->input_prev_weights[i], (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
  }

  // Allocate and copy hidden prev weights
  float **d_hidden_prev_weights_data;
  cudaMalloc(&d_hidden_prev_weights_data, (hid + 1) * (out + 1) * sizeof(float));
  for (int i = 0; i <= hid; i++) {
      d_hidden_prev_weights_ptr[i] = (float*)((char*)d_hidden_prev_weights_data + i * (out + 1) * sizeof(float));
      cudaMemcpy(d_hidden_prev_weights_ptr[i], net->hidden_prev_weights[i], (out + 1) * sizeof(float), cudaMemcpyHostToDevice);
  }

  // Layer forward pass
  int threadsPerBlock = 256;
  int blocksPerGrid_layer1 = (hid + threadsPerBlock - 1) / threadsPerBlock;
  bpnn_layerforward_kernel<<<blocksPerGrid_layer1, threadsPerBlock>>>(d_input_units, d_hidden_units, d_input_weights_ptr, in, hid);
  cudaDeviceSynchronize();

  int blocksPerGrid_layer2 = (out + threadsPerBlock - 1) / threadsPerBlock;
  bpnn_layerforward_kernel<<<blocksPerGrid_layer2, threadsPerBlock>>>(d_hidden_units, d_output_units, d_hidden_weights_ptr, hid, out);
  cudaDeviceSynchronize();

  // Compute error on output and hidden units
  float *d_out_err, *d_hid_err;
  cudaMalloc(&d_out_err, sizeof(float));
  cudaMalloc(&d_hid_err, sizeof(float));

  int blocksPerGrid_output_error = (out + threadsPerBlock - 1) / threadsPerBlock;
  bpnn_output_error_kernel<<<blocksPerGrid_output_error, threadsPerBlock>>>(d_output_delta, d_target, d_output_units, out, d_out_err);
  cudaDeviceSynchronize();

  int blocksPerGrid_hidden_error = (hid + threadsPerBlock - 1) / threadsPerBlock;
  bpnn_hidden_error_kernel<<<blocksPerGrid_hidden_error, threadsPerBlock>>>(d_hidden_delta, hid, d_output_delta, out, d_hidden_weights_ptr, d_hidden_units, d_hid_err);
  cudaDeviceSynchronize();

  // Adjust weights
  int blocksPerGrid_adjust_output = (out + threadsPerBlock - 1) / threadsPerBlock;
  bpnn_adjust_weights_kernel<<<blocksPerGrid_adjust_output, threadsPerBlock>>>(d_output_delta, out, d_hidden_units, hid, d_hidden_weights_ptr, d_hidden_prev_weights_ptr);
  cudaDeviceSynchronize();

  int blocksPerGrid_adjust_hidden = (hid + threadsPerBlock - 1) / threadsPerBlock;
  bpnn_adjust_weights_kernel<<<blocksPerGrid_adjust_hidden, threadsPerBlock>>>(d_hidden_delta, hid, d_input_units, in, d_input_weights_ptr, d_input_prev_weights_ptr);
  cudaDeviceSynchronize();

  // Copy results back to host
  cudaMemcpy(net->hidden_units, d_hidden_units, (hid + 1) * sizeof(float), cudaMemcpyDeviceToHost);
  cudaMemcpy(net->output_units, d_output_units, (out + 1) * sizeof(float), cudaMemcpyDeviceToHost);
  cudaMemcpy(net->hidden_delta, d_hidden_delta, (hid + 1) * sizeof(float), cudaMemcpyDeviceToHost);
  cudaMemcpy(net->output_delta, d_output_delta, (out + 1) * sizeof(float), cudaMemcpyDeviceToHost);

