////////////////////////////////////////////////////////////////////////////////
void BFSGraph( int argc, char** argv)
{
        int no_of_nodes = 0;
        int edge_list_size = 0;
        char *input_f;

	if(argc!=2){
	Usage(argc, argv);
	exit(0);
	}

	input_f = argv[1];

	printf("Reading File\n");
	//Read in Graph from a file
	FILE *fp = fopen(input_f,"r");
	if(!fp)
	{
		printf("Error Reading graph file\n");
		return;
	}

	int source = 0;

	fscanf(fp,"%d",&no_of_nodes);

	// allocate host memory
	Node* h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
	bool *h_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
	bool *h_updating_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
	bool *h_graph_visited = (bool*) malloc(sizeof(bool)*no_of_nodes);

	int start, edgeno;
	// initalize the memory
	for( unsigned int i = 0; i < no_of_nodes; i++)
	{
		fscanf(fp,"%d %d",&start,&edgeno);
		h_graph_nodes[i].starting = start;
		h_graph_nodes[i].no_of_edges = edgeno;
		h_graph_mask[i]=false;
		h_updating_graph_mask[i]=false;
		h_graph_visited[i]=false;
	}

	//read the source node from the file
	fscanf(fp,"%d",&source);
	// source=0; //tesing code line

	//set the source node as true in the mask
	h_graph_mask[source]=true;
	h_graph_visited[source]=true;

	fscanf(fp,"%d",&edge_list_size);

	int id,cost;
	int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
	for(int i=0; i < edge_list_size ; i++)
	{
		fscanf(fp,"%d",&id);
		fscanf(fp,"%d",&cost);
		h_graph_edges[i] = id;
	}

	if(fp)
		fclose(fp);


	// allocate mem for the result on host side
	int* h_cost = (int*) malloc( sizeof(int)*no_of_nodes);
	for(int i=0;i<no_of_nodes;i++)
		h_cost[i]=-1;
	h_cost[source]=0;

	printf("Start traversing the tree\n");

	// Allocate GPU memory
	Node *d_graph_nodes;
	bool *d_graph_mask;
	bool *d_updating_graph_mask;
	bool *d_graph_visited;
	int *d_graph_edges;
	int *d_cost;

	int num_nodes = no_of_nodes;
	int num_edges = edge_list_size;

	cudaMalloc((void**)&d_graph_nodes, sizeof(Node) * num_nodes);
	cudaMalloc((void**)&d_graph_mask, sizeof(bool) * num_nodes);
	cudaMalloc((void**)&d_updating_graph_mask, sizeof(bool) * num_nodes);
	cudaMalloc((void**)&d_graph_visited, sizeof(bool) * num_nodes);
	cudaMalloc((void**)&d_graph_edges, sizeof(int) * num_edges);
	cudaMalloc((void**)&d_cost, sizeof(int) * num_nodes);

	// Copy host data to device
	cudaMemcpy(d_graph_nodes, h_graph_nodes, sizeof(Node) * num_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_graph_mask, h_graph_mask, sizeof(bool) * num_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, sizeof(bool) * num_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_graph_visited, h_graph_visited, sizeof(bool) * num_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_graph_edges, h_graph_edges, sizeof(int) * num_edges, cudaMemcpyHostToDevice);
	cudaMemcpy(d_cost, h_cost, sizeof(int) * num_nodes, cudaMemcpyHostToDevice);

	// Kernel launch parameters
	int threadsPerBlock = 256;
	int blocksPerGrid = (num_nodes + threadsPerBlock - 1) / threadsPerBlock;

	bool stop = false;
	bool *d_stop;
	cudaMalloc((void**)&d_stop, sizeof(bool));

	int k = 0;
	do
	{
		//if no thread changes this value then the loop stops
		stop = false;
		cudaMemcpy(d_stop, &stop, sizeof(bool), cudaMemcpyHostToDevice);

		// Kernel 1: Process nodes in the current mask
		bfs_kernel1<<<blocksPerGrid, threadsPerBlock>>>(num_nodes, d_graph_nodes, d_graph_mask, d_graph_edges, d_graph_visited, d_cost, d_updating_graph_mask);
		cudaDeviceSynchronize(); // Ensure kernel 1 completes

		// Kernel 2: Update mask and visited status
		bfs_kernel2<<<blocksPerGrid, threadsPerBlock>>>(num_nodes, d_updating_graph_mask, d_graph_mask, d_graph_visited, d_stop);
		cudaDeviceSynchronize(); // Ensure kernel 2 completes

		// Copy stop flag back to host
		cudaMemcpy(&stop, d_stop, sizeof(bool), cudaMemcpyDeviceToHost);

		k++;
	} while (stop);

	// Copy result back to host
	cudaMemcpy(h_cost, d_cost, sizeof(int) * num_nodes, cudaMemcpyDeviceToHost);

	printf("Compute time: %lf\n", 0.0); // Placeholder for actual timing

	//Store the result into a file
	FILE *fpo = fopen("result.txt","w");
	for(int i=0;i<no_of_nodes;i++)
		fprintf(fpo,"%d) cost:%d\n",i,h_cost[i]);
	fclose(fpo);
	printf("Result stored in result.txt\n");


	// cleanup memory
	free( h_graph_nodes);
	free( h_graph_edges);
	free( h_graph_mask);
	free( h_updating_graph_mask);
	free( h_graph_visited);
	free( h_cost);

	// Free GPU memory
	cudaFree(d_graph_nodes);
	cudaFree(d_graph_mask);
	cudaFree(d_updating_graph_mask);
	cudaFree(d_graph_visited);
	cudaFree(d_graph_edges);
	cudaFree(d_cost);
	cudaFree(d_stop);
}

