// Copyright 2009, Andrew Corrigan, acorriga@gmu.edu
// This code is from the AIAA-2009-4001 paper

#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <algorithm> // For std::min

#ifndef block_length
#define block_length 1
#endif

#define GAMMA 1.4
#define iterations 2000

#define NDIM 3
#define NNB 4

#define RK 3	// 3rd order RK
#define ff_mach 1.2
#define deg_angle_of_attack 0.0f

#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

#define CUDA_CALL(call) do { \
    cudaError_t err = call; \
    if (err != cudaSuccess) { \
        fprintf(stderr, "CUDA error in %s at line %d: %s\n", __FILE__, __LINE__, cudaGetErrorString(err)); \
        exit(EXIT_FAILURE); \
    } \
} while (0)

struct float3 { float x, y, z; };

// Device functions
__device__ inline void compute_velocity_device(float& density, float3& momentum, float3& velocity)
{
	velocity.x = momentum.x / density;
	velocity.y = momentum.y / density;
	velocity.z = momentum.z / density;
}

__device__ inline float compute_speed_sqd_device(float3& velocity)
{
	return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

__device__ inline float compute_pressure_device(float& density, float& density_energy, float& speed_sqd)
{
	return (float(GAMMA)-float(1.0f))*(density_energy - float(0.5f)*density*speed_sqd);
}

__device__ inline float compute_speed_of_sound_device(float& density, float& pressure)
{
	return sqrtf(float(GAMMA)*pressure/density);
}

__device__ inline void compute_flux_contribution_device(float& density, float3& momentum, float& density_energy, float& pressure, float3& velocity, float3& fc_momentum_x, float3& fc_momentum_y, float3& fc_momentum_z, float3& fc_density_energy)
{
	fc_momentum_x.x = velocity.x*momentum.x + pressure;
	fc_momentum_x.y = velocity.x*momentum.y;
	fc_momentum_x.z = velocity.x*momentum.z;

	fc_momentum_y.x = fc_momentum_x.y;
	fc_momentum_y.y = velocity.y*momentum.y + pressure;
	fc_momentum_y.z = velocity.y*momentum.z;

	fc_momentum_z.x = fc_momentum_x.z;
	fc_momentum_z.y = fc_momentum_y.z;
	fc_momentum_z.z = velocity.z*momentum.z + pressure;

	float de_p = density_energy+pressure;
	fc_density_energy.x = velocity.x*de_p;
	fc_density_energy.y = velocity.y*de_p;
	fc_density_energy.z = velocity.z*de_p;
}

// Kernel for compute_step_factor
__global__ void compute_step_factor_kernel(int nelr, const float* __restrict variables, const float* __restrict areas, float* __restrict step_factors)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < nelr) {
        float density = variables[i + VAR_DENSITY*nelr];

        float3 momentum;
        momentum.x = variables[i + (VAR_MOMENTUM+0)*nelr];
        momentum.y = variables[i + (VAR_MOMENTUM+1)*nelr];
        momentum.z = variables[i + (VAR_MOMENTUM+2)*nelr];

        float density_energy = variables[i + VAR_DENSITY_ENERGY*nelr];
        float3 velocity; compute_velocity_device(density, momentum, velocity);
        float speed_sqd      = compute_speed_sqd_device(velocity);
        float pressure       = compute_pressure_device(density, density_energy, speed_sqd);
        float speed_of_sound = compute_speed_of_sound_device(density, pressure);

        step_factors[i] = 0.5f / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
    }
}

// Kernel for compute_flux
__global__ void compute_flux_kernel(int nelr, const int* __restrict elements_surrounding_elements, const float* __restrict normals, const float* __restrict variables, const float* __restrict ff_variable, const float3 ff_flux_contribution_momentum_x, const float3 ff_flux_contribution_momentum_y, const float3 ff_flux_contribution_momentum_z, const float3 ff_flux_contribution_density_energy, float* __restrict fluxes)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < nelr) {
        const float smoothing_coefficient = 0.2f;

        float density_i = variables[i + VAR_DENSITY*nelr];
        float3 momentum_i;
        momentum_i.x = variables[i + (VAR_MOMENTUM+0)*nelr];
        momentum_i.y = variables[i + (VAR_MOMENTUM+1)*nelr];
        momentum_i.z = variables[i + (VAR_MOMENTUM+2)*nelr];
        float density_energy_i = variables[i + VAR_DENSITY_ENERGY*nelr];

        float3 velocity_i; compute_velocity_device(density_i, momentum_i, velocity_i);
        float speed_sqd_i = compute_speed_sqd_device(velocity_i);
        float speed_i = sqrtf(speed_sqd_i);
        float pressure_i = compute_pressure_device(density_i, density_energy_i, speed_sqd_i);
        float speed_of_sound_i = compute_speed_of_sound_device(density_i, pressure_i);
        float3 flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
        float3 flux_contribution_i_density_energy;
        compute_flux_contribution_device(density_i, momentum_i, density_energy_i, pressure_i, velocity_i, flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z, flux_contribution_i_density_energy);

        float flux_i_density = 0.0f;
        float3 flux_i_momentum;
        flux_i_momentum.x = 0.0f;
        flux_i_momentum.y = 0.0f;
        flux_i_momentum.z = 0.0f;
        float flux_i_density_energy = 0.0f;

        float3 velocity_nb;
        float density_nb, density_energy_nb;
        float3 momentum_nb;
        float3 flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
        float3 flux_contribution_nb_density_energy;
        float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

        for(int j = 0; j < NNB; j++)
        {
            int nb = elements_surrounding_elements[i + j*nelr];
            float3 normal;
            normal.x = normals[i + (j + 0*NNB)*nelr];
            normal.y = normals[i + (j + 1*NNB)*nelr];
            normal.z = normals[i + (j + 2*NNB)*nelr];
            float normal_len = sqrtf(normal.x*normal.x + normal.y*normal.y + normal.z*normal.z);

            if(nb >= 0) 	// a legitimate neighbor
            {
                density_nb =        variables[nb + VAR_DENSITY*nelr];
                momentum_nb.x =     variables[nb + (VAR_MOMENTUM+0)*nelr];
                momentum_nb.y =     variables[nb + (VAR_MOMENTUM+1)*nelr];
                momentum_nb.z =     variables[nb + (VAR_MOMENTUM+2)*nelr];
                density_energy_nb = variables[nb + VAR_DENSITY_ENERGY*nelr];
                compute_velocity_device(density_nb, momentum_nb, velocity_nb);
                speed_sqd_nb                      = compute_speed_sqd_device(velocity_nb);
                pressure_nb                       = compute_pressure_device(density_nb, density_energy_nb, speed_sqd_nb);
                speed_of_sound_nb                 = compute_speed_of_sound_device(density_nb, pressure_nb);
                compute_flux_contribution_device(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb, flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z, flux_contribution_nb_density_energy);

                float factor = -normal_len*smoothing_coefficient*0.5f*(speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor*(density_i-density_nb);
                flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
                flux_i_momentum.x += factor*(momentum_i.x-momentum_nb.x);
                flux_i_momentum.y += factor*(momentum_i.y-momentum_nb.y);
                flux_i_momentum.z += factor*(momentum_i.z-momentum_nb.z);

                factor = 0.5f*normal.x;
                flux_i_density += factor*(momentum_nb.x+momentum_i.x);
                flux_i_density_energy += factor*(flux_contribution_nb_density_energy.x+flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.x+flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.x+flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.x+flux_contribution_i_momentum_z.x);

                factor = 0.5f*normal.y;
                flux_i_density += factor*(momentum_nb.y+momentum_i.y);
                flux_i_density_energy += factor*(flux_contribution_nb_density_energy.y+flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.y+flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.y+flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.y+flux_contribution_i_momentum_z.y);

                factor = 0.5f*normal.z;
                flux_i_density += factor*(momentum_nb.z+momentum_i.z);
                flux_i_density_energy += factor*(flux_contribution_nb_density_energy.z+flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.z+flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.z+flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.z+flux_contribution_i_momentum_z.z);
            }
            else if(nb == -1)	// a wing boundary
            {
                flux_i_momentum.x += normal.x*pressure_i;
                flux_i_momentum.y += normal.y*pressure_i;
                flux_i_momentum.z += normal.z*pressure_i;
            }
            else if(nb == -2) // a far field boundary
            {
                factor = 0.5f*normal.x;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i.x);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy.x+flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor*(ff_flux_contribution_momentum_x.x + flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor*(ff_flux_contribution_momentum_y.x + flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor*(ff_flux_contribution_momentum_z.x + flux_contribution_i_momentum_z.x);

                factor = 0.5f*normal.y;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i.y);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy.y+flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor*(ff_flux_contribution_momentum_x.y + flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor*(ff_flux_contribution_momentum_y.y + flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor*(ff_flux_contribution_momentum_z.y + flux_contribution_i_momentum_z.y);

                factor = 0.5f*normal.z;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i.z);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy.z+flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor*(ff_flux_contribution_momentum_x.z + flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor*(ff_flux_contribution_momentum_y.z + flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor*(ff_flux_contribution_momentum_z.z + flux_contribution_i_momentum_z.z);
            }
        }
        fluxes[i + VAR_DENSITY*nelr] = flux_i_density;
        fluxes[i + (VAR_MOMENTUM+0)*nelr] = flux_i_momentum.x;
        fluxes[i + (VAR_MOMENTUM+1)*nelr] = flux_i_momentum.y;
        fluxes[i + (VAR_MOMENTUM+2)*nelr] = flux_i_momentum.z;
        fluxes[i + VAR_DENSITY_ENERGY*nelr] = flux_i_density_energy;
    }
}

// Kernel for time_step
__global__ void time_step_kernel(int nelr, const float* __restrict old_variables, float* __restrict variables, const float* __restrict step_factors, const float* __restrict fluxes, int j)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < nelr) {
        float factor = step_factors[i] / float(RK+1-j);

        variables[i + VAR_DENSITY*nelr] = old_variables[i + VAR_DENSITY*nelr] + factor*fluxes[i + VAR_DENSITY*nelr];
        variables[i + (VAR_MOMENTUM+0)*nelr] = old_variables[i + (VAR_MOMENTUM+0)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+0)*nelr];
        variables[i + (VAR_MOMENTUM+1)*nelr] = old_variables[i + (VAR_MOMENTUM+1)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+1)*nelr];
        variables[i + (VAR_MOMENTUM+2)*nelr] = old_variables[i + (VAR_MOMENTUM+2)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+2)*nelr];
        variables[i + VAR_DENSITY_ENERGY*nelr] = old_variables[i + VAR_DENSITY_ENERGY*nelr] + factor*fluxes[i + VAR_DENSITY_ENERGY*nelr];
    }
}

// Kernel for initialize_variables
__global__ void initialize_variables_kernel(int nelr, const float* ff_variable, float* variables)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < nelr) {
        for(int j = 0; j < NVAR; j++) {
            variables[i + j*nelr] = ff_variable[j];
        }
    }
}

// Kernel for copy
__global__ void copy_kernel(float* dst, const float* src, int N)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < N) {
        dst[i] = src[i];
    }
}

// Host functions
void dump(float* variables, int nel, int nelr)
{
	FILE *file;

	file = fopen("density", "w");
	fprintf(file, "%d %d\n", nel, nelr);
	for(int i = 0; i < nel; i++) fprintf(file, "%f\n", variables[i + VAR_DENSITY*nelr]);
	fclose(file);

	file = fopen("momentum", "w");
	fprintf(file, "%d %d\n", nel, nelr);
	for(int i = 0; i < nel; i++)
	{
		for(int j = 0; j != NDIM; j++) fprintf(file, "%f ", variables[i + (VAR_MOMENTUM+j)*nelr]);
		fprintf(file, "\n");
	}
	fclose(file);

	file = fopen("density_energy", "w");
	fprintf(file, "%d %d\n", nel, nelr);
	for(int i = 0; i < nel; i++) fprintf(file, "%f\n", variables[i + VAR_DENSITY_ENERGY*nelr]);
	fclose(file);
}

void initialize_variables(int nelr, float* variables, float* ff_variable)
{
    dim3 blockDim(256);
    dim3 gridDim((nelr + blockDim.x - 1) / blockDim.x);
    initialize_variables_kernel<<<gridDim, blockDim>>>(nelr, ff_variable, variables);
    CUDA_CALL(cudaGetLastError());
    CUDA_CALL(cudaDeviceSynchronize());
}

void compute_step_factor(int nelr, float* variables, float* areas, float* step_factors)
{
    dim3 blockDim(256);
    dim3 gridDim((nelr + blockDim.x - 1) / blockDim.x);
    compute_step_factor_kernel<<<gridDim, blockDim>>>(nelr, variables, areas, step_factors);
    CUDA_CALL(cudaGetLastError());
    CUDA_CALL(cudaDeviceSynchronize());
}

void compute_flux(int nelr, int* elements_surrounding_elements, float* normals, float* variables, float* ff_variable, float3 ff_flux_contribution_momentum_x, float3 ff_flux_contribution_momentum_y, float3 ff_flux_contribution_momentum_z, float3 ff_flux_contribution_density_energy, float* fluxes)
{
    dim3 blockDim(256);
    dim3 gridDim((nelr + blockDim.x - 1) / blockDim.x);
    compute_flux_kernel<<<gridDim, blockDim>>>(nelr, elements_surrounding_elements, normals, variables, ff_variable, ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z, ff_flux_contribution_density_energy, fluxes);
    CUDA_CALL(cudaGetLastError());
    CUDA_CALL(cudaDeviceSynchronize());
}

void time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes)
{
    dim3 blockDim(256);
    dim3 gridDim((nelr + blockDim.x - 1) / blockDim.x);
    time_step_kernel<<<gridDim, blockDim>>>(nelr, old_variables, variables, step_factors, fluxes, j);
    CUDA_CALL(cudaGetLastError());
    CUDA_CALL(cudaDeviceSynchronize());
}

void copy(float* dst, float* src, int N)
{
    dim3 blockDim(256);
    dim3 gridDim((N + blockDim.x - 1) / blockDim.x);
    copy_kernel<<<gridDim, blockDim>>>(dst, src, N);
    CUDA_CALL(cudaGetLastError());
    CUDA_CALL(cudaDeviceSynchronize());
}

// Main function
int main(int argc, char** argv)
{
	if (argc < 2)
	{
		printf("specify data file name\n");
		return 0;
	}
	const char* data_file_name = argv[1];

    float ff_variable[NVAR];
    float3 ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z, ff_flux_contribution_density_energy;

	// set far field conditions
	{
		const float angle_of_attack = (3.1415926535897931 / 180.0f) * deg_angle_of_attack;

		ff_variable[VAR_DENSITY] = 1.4f;

		float ff_pressure = 1.0f;
		float ff_speed_of_sound = sqrtf(GAMMA*ff_pressure / ff_variable[VAR_DENSITY]);
		float ff_speed = ff_mach*ff_speed_of_sound;

		float3 ff_velocity;
		ff_velocity.x = ff_speed*cosf(angle_of_attack);
		ff_velocity.y = ff_speed*sinf(angle_of_attack);
		ff_velocity.z = 0.0f;

		ff_variable[VAR_MOMENTUM+0] = ff_variable[VAR_DENSITY] * ff_velocity.x;
		ff_variable[VAR_MOMENTUM+1] = ff_variable[VAR_DENSITY] * ff_velocity.y;
		ff_variable[VAR_MOMENTUM+2] = ff_variable[VAR_DENSITY] * ff_velocity.z;

		ff_variable[VAR_DENSITY_ENERGY] = ff_variable[VAR_DENSITY]*(0.5f*(ff_speed*ff_speed)) + (ff_pressure / (GAMMA-1.0f));

		float3 ff_momentum;
		ff_momentum.x = *(ff_variable+VAR_MOMENTUM+0);
		ff_momentum.y = *(ff_variable+VAR_MOMENTUM+1);
		ff_momentum.z = *(ff_variable+VAR_MOMENTUM+2);
		compute_flux_contribution_device(ff_variable[VAR_DENSITY], ff_momentum, ff_variable[VAR_DENSITY_ENERGY], ff_pressure, ff_velocity, ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z, ff_flux_contribution_density_energy);
	}
	int nel;
	int nelr;

	float* areas;
	int* elements_surrounding_elements;
	float* normals;
	{
		FILE *file = fopen(data_file_name, "r");
        if (!file) {
            fprintf(stderr, "Error opening file %s\n", data_file_name);
            return 1;
        }

		if (fscanf(file, "%d", &nel) != 1) { fprintf(stderr, "Error reading nel\n"); return 1; }
		nelr = block_length*((nel / block_length )+ std::min(1, nel % block_length));

		areas = (float*)malloc(nelr * sizeof(float));
		elements_surrounding_elements = (int*)malloc(nelr*NNB * sizeof(int));
		normals = (float*)malloc(NDIM*NNB*nelr * sizeof(float));

		for(int i = 0; i < nel; i++)
		{
			if (fscanf(file, "%f", &areas[i]) != 1) { fprintf(stderr, "Error reading areas[%d]\n", i); return 1; }
			for(int j = 0; j < NNB; j++)
			{
				if (fscanf(file, "%d", &elements_surrounding_elements[i + j*nelr]) != 1) { fprintf(stderr, "Error reading elements_surrounding_elements[%d][%d]\n", i, j); return 1; }
				if(elements_surrounding_elements[i+j*nelr] < 0) elements_surrounding_elements[i+j*nelr] = -1;
				elements_surrounding_elements[i + j*nelr]--; //it's coming in with Fortran numbering

				for(int k = 0; k < NDIM; k++)
				{
					if (fscanf(file, "%f", &normals[i + (j + k*NNB)*nelr]) != 1) { fprintf(stderr, "Error reading normals[%d][%d][%d]\n", i, j, k); return 1; }
					normals[i + (j + k*NNB)*nelr] = -normals[i + (j + k*NNB)*nelr];
				}
			}
		}
        fclose(file);

		int last = nel-1;
		for(int i = nel; i < nelr; i++)
		{
			areas[i] = areas[last];
			for(int j = 0; j < NNB; j++)
			{
				elements_surrounding_elements[i + j*nelr] = elements_surrounding_elements[last + j*nelr];
				for(int k = 0; k < NDIM; k++) normals[i + (j + k*NNB)*nelr] = normals[last + (j + k*NNB)*nelr];
			}
		}
	}

    float* variables;
    float* old_variables;
    float* fluxes;
    float* step_factors;

    size_t variables_size = (size_t)nelr * NVAR * sizeof(float);
    size_t step_factors_size = (size_t)nelr * sizeof(float);
    size_t elements_surrounding_elements_size = (size_t)nelr * NNB * sizeof(int);
    size_t normals_size = (size_t)NDIM * NNB * nelr * sizeof(float);
    size_t areas_size = (size_t)nelr * sizeof(float);

    // Allocate host memory
    variables = (float*)malloc(variables_size);
    old_variables = (float*)malloc(variables_size);
    fluxes = (float*)malloc(variables_size);
    step_factors = (float*)malloc(step_factors_size);

    // Allocate device memory
    float *d_variables, *d_old_variables, *d_fluxes, *d_step_factors;
    int *d_elements_surrounding_elements;
    float *d_areas, *d_normals;

    CUDA_CALL(cudaMalloc(&d_variables, variables_size));
    CUDA_CALL(cudaMalloc(&d_old_variables, variables_size));
    CUDA_CALL(cudaMalloc(&d_fluxes, variables_size));
    CUDA_CALL(cudaMalloc(&d_step_factors, step_factors_size));
    CUDA_CALL(cudaMalloc(&d_elements_surrounding_elements, elements_surrounding_elements_size));
    CUDA_CALL(cudaMalloc(&d_areas, areas_size));
    CUDA_CALL(cudaMalloc(&d_normals, normals_size));

    // Copy data to device
    CUDA_CALL(cudaMemcpy(d_areas, areas, areas_size, cudaMemcpyHostToDevice));
    CUDA_CALL(cudaMemcpy(d_elements_surrounding_elements, elements_surrounding_elements, elements_surrounding_elements_size, cudaMemcpyHostToDevice));
    CUDA_CALL(cudaMemcpy(d_normals, normals, normals_size, cudaMemcpyHostToDevice));

	initialize_variables(nelr, variables, ff_variable);
    copy(variables, variables, nelr*NVAR); // Copy initial variables to device

	printf("Starting...\n");
    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);
    cudaEventRecord(start);

	for(int i = 0; i < iterations; i++)
	{
        copy(old_variables, variables, nelr*NVAR); // Copy current variables to old_variables on host, then to device
        CUDA_CALL(cudaMemcpy(d_old_variables, old_variables, variables_size, cudaMemcpyHostToDevice));
        CUDA_CALL(cudaMemcpy(d_variables, variables, variables_size, cudaMemcpyHostToDevice)); // Ensure d_variables is up-to-date

		compute_step_factor(nelr, variables, areas, step_factors);
        CUDA_CALL(cudaMemcpy(d_step_factors, step_factors, step_factors_size, cudaMemcpyHostToDevice));

		for(int j = 0; j < RK; j++)
		{
			compute_flux(nelr, elements_surrounding_elements, normals, variables, ff_variable, ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z, ff_flux_contribution_density_energy, fluxes);
            CUDA_CALL(cudaMemcpy(d_fluxes, fluxes, variables_size, cudaMemcpyHostToDevice));
			time_step(j, nelr, d_old_variables, d_variables, d_step_factors, d_fluxes);
		}
        CUDA_CALL(cudaMemcpy(variables, d_variables, variables_size, cudaMemcpyDeviceToHost)); // Copy back results for next iteration
	}

    cudaEventRecord(stop);
    cudaEventSynchronize(stop);
    float milliseconds = 0;
    cudaEventElapsedTime(&milliseconds, start, stop);
	printf("Compute time: %f seconds\n", milliseconds / 1000.0f);

	printf("Saving solution...\n");
	dump(variables, nel, nelr);
	printf("Saved solution...\n");

	printf("Cleaning up...\n");
	free(areas);
	free(elements_surrounding_elements);
	free(normals);

	free(variables);
	free(old_variables);
	free(fluxes);
	free(step_factors);

    CUDA_CALL(cudaFree(d_variables));
    CUDA_CALL(cudaFree(d_old_variables));
    CUDA_CALL(cudaFree(d_fluxes));
    CUDA_CALL(cudaFree(d_step_factors));
    CUDA_CALL(cudaFree(d_elements_surrounding_elements));
    CUDA_CALL(cudaFree(d_areas));
    CUDA_CALL(cudaFree(d_normals));

	printf("Done...\n");

	return 0;
}

