__global__ void kernel_gpu(public_struct public,
                           private_struct private){

	//======================================================================================================================================================
	//	COMMON VARIABLES
	//======================================================================================================================================================

	int ei_new;
	fp* d_in;
	int rot_row;
	int rot_col;
	int in2_rowlow;
	int in2_collow;
