#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda_runtime.h>

#define BLOCK_SIZE 16

// CUDA kernel for the Needleman-Wunsch algorithm
__global__ void nw_kernel(int *input_itemsets, int *referrence, int max_cols, int penalty) {
    // Shared memory for blocks
    extern __shared__ int shared_mem[];
    int *input_itemsets_l = shared_mem;
    int *reference_l = input_itemsets_l + (BLOCK_SIZE + 1) * (BLOCK_SIZE + 1);

    // Block and thread indices
    int block_idx_x = blockIdx.x;
    int block_idx_y = blockIdx.y;
    int tid_x = threadIdx.x;
    int tid_y = threadIdx.y;

    // Calculate global indices for input_itemsets and reference
    int global_row_start = block_idx_y * BLOCK_SIZE;
    int global_col_start = block_idx_x * BLOCK_SIZE;

    // Load reference data into shared memory
    int ref_row_idx = global_row_start + tid_y + 1;
    int ref_col_idx = global_col_start + tid_x + 1;
    if (ref_row_idx < max_cols && ref_col_idx < max_cols) {
        reference_l[tid_y * BLOCK_SIZE + tid_x] = referrence[max_cols * ref_row_idx + ref_col_idx];
    } else {
        reference_l[tid_y * BLOCK_SIZE + tid_x] = 0; // Should not be accessed if bounds are checked
    }

    // Load input_itemsets data into shared memory
    int input_row_start_idx = global_row_start + tid_y;
    int input_col_start_idx = global_col_start + tid_x;
    if (input_row_start_idx < max_cols && input_col_start_idx < max_cols) {
        input_itemsets_l[tid_y * (BLOCK_SIZE + 1) + tid_x] = input_itemsets[max_cols * input_row_start_idx + input_col_start_idx];
    } else {
        input_itemsets_l[tid_y * (BLOCK_SIZE + 1) + tid_x] = 0; // Should not be accessed if bounds are checked
    }

    // Load the first row and column of the block's input_itemsets_l
    int input_row_first_col_idx = global_row_start + tid_y;
    int input_col_first_row_idx = global_col_start + tid_x;
    if (tid_x == 0 && input_row_first_col_idx < max_cols) {
        input_itemsets_l[tid_y * (BLOCK_SIZE + 1) + 0] = input_itemsets[max_cols * input_row_first_col_idx + 0];
    }
    if (tid_y == 0 && input_col_first_row_idx < max_cols) {
        input_itemsets_l[0 * (BLOCK_SIZE + 1) + tid_x] = input_itemsets[max_cols * 0 + input_col_first_row_idx];
    }
    __syncthreads();

    // Compute within the block
    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            int current_block_row = global_row_start + i;
            int current_block_col = global_col_start + j;

            if (current_block_row < max_cols && current_block_col < max_cols) {
                int diag = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1];
                int left = input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1];
                int up = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j];
                int match_score = reference_l[(i - 1) * BLOCK_SIZE + j - 1];

                input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = max(diag + match_score, max(left - penalty, up - penalty));
            }
        }
        __syncthreads();
    }

    // Store results back to global memory
    int output_row_idx = global_row_start + tid_y + 1;
    int output_col_idx = global_col_start + tid_x + 1;
    if (output_row_idx < max_cols && output_col_idx < max_cols) {
        input_itemsets[max_cols * output_row_idx + output_col_idx] = input_itemsets_l[(tid_y + 1) * (BLOCK_SIZE + 1) + (tid_x + 1)];
    }
}

// Wrapper function to launch the CUDA kernel
void nw_optimized_cuda(int *input_itemsets, int *referrence, int max_rows, int max_cols, int penalty) {
    int size = max_rows * max_cols * sizeof(int);
    int *d_input_itemsets, *d_referrence;

    // Allocate memory on the device
    cudaMalloc(&d_input_itemsets, size);
    cudaMalloc(&d_referrence, size);

    // Copy data from host to device
    cudaMemcpy(d_input_itemsets, input_itemsets, size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_referrence, referrence, size, cudaMemcpyHostToDevice);

    // Define block and grid dimensions
    // The number of blocks should cover the entire matrix, excluding the first row and column
    dim3 blockDim(BLOCK_SIZE, BLOCK_SIZE);
    dim3 gridDim((max_cols - 1 + BLOCK_SIZE - 1) / BLOCK_SIZE, (max_rows - 1 + BLOCK_SIZE - 1) / BLOCK_SIZE);

    // Calculate shared memory size per block
    size_t sharedMemSize = (BLOCK_SIZE + 1) * (BLOCK_SIZE + 1) * sizeof(int) + BLOCK_SIZE * BLOCK_SIZE * sizeof(int);

    // Launch the kernel
    nw_kernel<<<gridDim, blockDim, sharedMemSize>>>(d_input_itemsets, d_referrence, max_cols, penalty);

    // Synchronize to ensure kernel completion
    cudaDeviceSynchronize();

    // Copy results from device to host
    cudaMemcpy(input_itemsets, d_input_itemsets, size, cudaMemcpyDeviceToHost);

    // Free device memory
    cudaFree(d_input_itemsets);
    cudaFree(d_referrence);
}

// Helper function to call the CUDA optimized version
void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
        int max_rows, int max_cols, int penalty)
{
    nw_optimized_cuda(input_itemsets, referrence, max_rows, max_cols, penalty);
}

