#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <string.h> // For strcmp and sscanf
#include <time.h>   // For time()
#include <sys/time.h> // For gettimeofday

#define PI 3.1415926535897932

// --- Timing Functions (Host-side) ---
long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

float elapsed_time(long long start_time, long long end_time) {
    return (float)(end_time - start_time) / (1000 * 1000);
}

// --- CUDA Helper Functions ---
void checkCudaErrors(cudaError_t err, const char *file, int line) {
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA error at %s:%d: %s\n", file, line, cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }
}
#define CUDA_CHECK(err) checkCudaErrors(err, __FILE__, __LINE__)

// --- Device-side Utility Functions ---
__device__ double roundDouble_device(double value) {
    return round(value);
}

__device__ double randu_device(unsigned int *seed, unsigned int index) {
    unsigned int num = 1103515245 * seed[index] + 12345;
    seed[index] = num % 2147483647; // Using INT_MAX as modulus
    return fabs((double)seed[index] / 2147483647.0);
}

__device__ double randn_device(unsigned int *seed, unsigned int index) {
    double u = randu_device(seed, index);
    double v = randu_device(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

// --- CUDA Kernels ---

// Kernel for initializing video sequence
__global__ void videoSequence_kernel(int *I, int IszX, int IszY, int Nfr, unsigned int *seed) {
    int k = blockIdx.x; // Each block processes one frame

    if (k >= Nfr) return;

    int max_size = IszX * IszY * Nfr;
    int x0 = IszY / 2;
    int y0 = IszX / 2;

    // Set initial point
    if (k == 0) {
        I[x0 * IszY * Nfr + y0 * Nfr + k] = 1;
    }

    // Move point
    int xk = abs(x0 + (k - 1));
    int yk = abs(y0 - 2 * (k - 1));
    int pos = yk * IszY * Nfr + xk * Nfr + k;
    if (pos < max_size) {
        I[pos] = 1;
    }
}

// Kernel for dilating a single pixel's neighborhood
__global__ void dilate_matrix_kernel(int *matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = max(0, posX - error);
    int startY = max(0, posY - error);
    int endX = min(dimX, posX + error);
    int endY = min(dimY, posY + error);

    for (int x = startX; x < endX; ++x) {
        for (int y = startY; y < endY; ++y) {
            double distance = sqrt(pow((double)(x - posX), 2) + pow((double)(y - posY), 2));
            if (distance < error) {
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
            }
        }
    }
}

// Kernel for performing dilation across the entire frame
__global__ void imdilate_disk_kernel(const int *matrix, int dimX, int dimY, int dimZ, int error, int *newMatrix) {
    int z = blockIdx.z;
    int x = blockIdx.x;
    int y = threadIdx.x;

    if (z >= dimZ || x >= dimX || y >= dimY) return;

    if (matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
        // Launch a kernel for each pixel that needs dilation
        // This is a naive approach; a more optimized version would use shared memory or warp primitives.
        dilate_matrix_kernel<<<1, 1>>>(newMatrix, x, y, z, dimX, dimY, dimZ, error);
    }
}

// Kernel for setting values in the 3D array
__global__ void setIf_kernel(int *array3D, int dimX, int dimY, int dimZ, int testValue, int newValue) {
    int idx = blockIdx.x;
    if (idx >= dimX * dimY * dimZ) return;

    if (array3D[idx] == testValue) {
        array3D[idx] = newValue;
    }
}

// Kernel for adding noise to the 3D array
__global__ void addNoise_kernel(int *array3D, int dimX, int dimY, int dimZ, unsigned int *seed) {
    int idx = blockIdx.x;
    if (idx >= dimX * dimY * dimZ) return;

    array3D[idx] = array3D[idx] + (int)(5 * randn_device(seed, idx));
}

// Kernel for calculating indices for particle filter likelihood
__global__ void calculate_indices_kernel(int *ind, const double *arrayX, const double *arrayY, const double *objxy, int countOnes, int Nparticles, int k, int IszY, int Nfr, int max_size) {
    int particle_idx = blockIdx.x;
    int neighbor_idx = threadIdx.x;

    if (particle_idx >= Nparticles || neighbor_idx >= countOnes) return;

    double current_arrayX = arrayX[particle_idx];
    double current_arrayY = arrayY[particle_idx];

    int indX = roundDouble_device(current_arrayX) + (int)objxy[neighbor_idx * 2 + 1];
    int indY = roundDouble_device(current_arrayY) + (int)objxy[neighbor_idx * 2];

    int current_ind = indX * IszY * Nfr + indY * Nfr + k;

    // Ensure index is within bounds
    if (current_ind < 0 || current_ind >= max_size) {
        current_ind = 0; // Default to 0 if out of bounds
    }
    ind[particle_idx * countOnes + neighbor_idx] = current_ind;
}

// Kernel for calculating likelihood sum for each particle
__global__ void calcLikelihoodSum_kernel(const int *I, const int *ind, int numOnes, double *likelihood_out, int particle_idx, int Nparticles, int countOnes, int k, int IszY, int Nfr, int max_size) {
    int y = threadIdx.x;
    if (y >= numOnes) return;

    int current_ind_idx = particle_idx * numOnes + y;
    int current_ind = ind[current_ind_idx];

    // Ensure index is within bounds
    if (current_ind < 0 || current_ind >= max_size) {
        likelihood_out[particle_idx] = -1e9; // Assign a very small likelihood for invalid indices
        return;
    }

    double term1 = pow((double)(I[current_ind] - 100), 2);
    double term2 = pow((double)(I[current_ind] - 228), 2);
    double current_likelihood = (term1 - term2) / 50.0;

    // Accumulate likelihood for the current particle
    atomicAdd(&likelihood_out[particle_idx], current_likelihood);
}

// Kernel for applying motion model
__global__ void apply_motion_model_kernel(double *arrayX, double *arrayY, int Nparticles, unsigned int *seed) {
    int idx = blockIdx.x;
    if (idx >= Nparticles) return;
    arrayX[idx] += 1.0 + 5.0 * randn_device(seed, idx);
    arrayY[idx] += -2.0 + 2.0 * randn_device(seed, idx);
}

// Kernel for updating weights
__global__ void update_weights_kernel(double *weights, const double *likelihood, int Nparticles) {
    int idx = blockIdx.x;
    if (idx >= Nparticles) return;
    weights[idx] *= exp(likelihood[idx]);
}

// Kernel for normalizing weights
__global__ void normalize_weights_kernel(double *weights, double sumWeights, int Nparticles) {
    int idx = blockIdx.x;
    if (idx >= Nparticles) return;
    weights[idx] /= sumWeights;
}

// Kernel for calculating new object center (xe, ye)
__global__ void estimate_object_location_kernel(double *xe, double *ye, const double *arrayX, const double *arrayY, const double *weights, int Nparticles) {
    int idx = blockIdx.x;
    if (idx >= Nparticles) return;
    atomicAdd(xe, arrayX[idx] * weights[idx]);
    atomicAdd(ye, arrayY[idx] * weights[idx]);
}

// Kernel for calculating CDF
__global__ void calculate_CDF_kernel(const double *weights, double *CDF, int Nparticles) {
    int idx = blockIdx.x;
    if (idx >= Nparticles) return;
    if (idx == 0) {
        CDF[idx] = weights[idx];
    } else {
        CDF[idx] = weights[idx] + CDF[idx - 1];
    }
}

// Kernel for calculating u
__global__ void calculate_u_kernel(double *u, double u1, int Nparticles) {
    int idx = blockIdx.x;
    if (idx >= Nparticles) return;
    u[idx] = u1 + (double)idx / (double)Nparticles;
}

// Kernel for resampling (finding new xj, yj)
__global__ void resample_kernel(double *xj, double *yj, const double *arrayX, const double *arrayY, const double *CDF, const double *u, int Nparticles) {
    int j = blockIdx.x;
    if (j >= Nparticles) return;

    int i = 0;
    // Sequential search for i in CDF
    while (i < Nparticles && CDF[i] < u[j]) {
        i++;
    }
    if (i == Nparticles) {
        i = Nparticles - 1;
    }

    xj[j] = arrayX[i];
    yj[j] = arrayY[i];
}

// Kernel for resetting weights and assigning new xj, yj to arrayX, arrayY
__global__ void reset_particles_kernel(double *arrayX, double *arrayY, double *weights, const double *xj, const double *yj, int Nparticles) {
    int idx = blockIdx.x;
    if (idx >= Nparticles) return;
    arrayX[idx] = xj[idx];
    arrayY[idx] = yj[idx];
    weights[idx] = 1.0 / (double)Nparticles;
}

// --- Host-side Particle Filter Function ---
void particleFilter(int *I_host, int IszX, int IszY, int Nfr, unsigned int *seed_host, int Nparticles) {
    int max_size = IszX * IszY * Nfr;
    long long start = get_time();

    // --- Host to Device Memory Allocation ---
    int *I_device;
    unsigned int *seed_device;
    double *weights_device, *likelihood_device, *arrayX_device, *arrayY_device, *xj_device, *yj_device, *CDF_device, *u_device;
    int *ind_device;
    double *objxy_device;
    int *disk_device;

    CUDA_CHECK(cudaMalloc(&I_device, sizeof(int) * max_size));
    CUDA_CHECK(cudaMalloc(&seed_device, sizeof(unsigned int) * Nparticles));
    CUDA_CHECK(cudaMalloc(&weights_device, sizeof(double) * Nparticles));
    CUDA_CHECK(cudaMalloc(&likelihood_device, sizeof(double) * Nparticles));
    CUDA_CHECK(cudaMalloc(&arrayX_device, sizeof(double) * Nparticles));
    CUDA_CHECK(cudaMalloc(&arrayY_device, sizeof(double) * Nparticles));
    CUDA_CHECK(cudaMalloc(&xj_device, sizeof(double) * Nparticles));
    CUDA_CHECK(cudaMalloc(&yj_device, sizeof(double) * Nparticles));
    CUDA_CHECK(cudaMalloc(&CDF_device, sizeof(double) * Nparticles));
    CUDA_CHECK(cudaMalloc(&u_device, sizeof(double) * Nparticles));

    // Prepare disk structure (host-side)
    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk_host = (int *)malloc(diameter * diameter * sizeof(int));
    int countOnes = 0;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) + pow((double)(y - radius + 1), 2));
            if (distance < radius) {
                disk_host[x * diameter + y] = 1;
                countOnes++;
            } else {
                disk_host[x * diameter + y] = 0;
            }
        }
    }
    CUDA_CHECK(cudaMalloc(&disk_device, sizeof(int) * diameter * diameter));
    CUDA_CHECK(cudaMemcpy(disk_device, disk_host, sizeof(int) * diameter * diameter, cudaMemcpyHostToDevice));

    // Prepare object offsets (host-side)
    double *objxy_host = (double *)malloc(countOnes * 2 * sizeof(double));
    int neighY = 0;
    int center = radius - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (disk_host[x * diameter + y]) {
                objxy_host[neighY * 2] = (double)(y - center);
                objxy_host[neighY * 2 + 1] = (double)(x - center);
                neighY++;
            }
        }
    }
    CUDA_CHECK(cudaMalloc(&objxy_device, sizeof(double) * countOnes * 2));
    CUDA_CHECK(cudaMemcpy(objxy_device, objxy_host, sizeof(double) * countOnes * 2, cudaMemcpyHostToDevice));

    // Allocate index array on device
    CUDA_CHECK(cudaMalloc(&ind_device, sizeof(int) * countOnes * Nparticles));

    // Copy input video data to device
    CUDA_CHECK(cudaMemcpy(I_device, I_host, sizeof(int) * max_size, cudaMemcpyHostToDevice));
    // Copy seed data to device
    CUDA_CHECK(cudaMemcpy(seed_device, seed_host, sizeof(unsigned int) * Nparticles, cudaMemcpyHostToDevice));

    // Initial weights
    double initial_weight = 1.0 / (double)Nparticles;
    for (int i = 0; i < Nparticles; ++i) {
        weights_device[i] = initial_weight;
    }

    // Initial particle positions
    double xe_host = roundDouble_device(IszY / 2.0);
    double ye_host = roundDouble_device(IszX / 2.0);
    for (int i = 0; i < Nparticles; ++i) {
        arrayX_device[i] = xe_host;
        arrayY_device[i] = ye_host;
    }

    long long get_neighbors_time = get_time();
    printf("TIME TO GET NEIGHBORS TOOK: %f\n", elapsed_time(start, get_neighbors_time));

    long long get_weights_time = get_time();
    printf("TIME TO GET WEIGHTS TOOK: %f\n", elapsed_time(get_neighbors_time, get_weights_time));

    long long set_arrays_time = get_time();
    printf("TIME TO SET ARRAYS TOOK: %f\n", elapsed_time(get_weights_time, set_arrays_time));

    // --- Main Particle Filter Loop ---
    for (int k = 1; k < Nfr; k++) {
        long long frame_start_time = get_time();

        // Apply motion model
        int threadsPerBlockMotion = 256;
        int numBlocksMotion = (Nparticles + threadsPerBlockMotion - 1) / threadsPerBlockMotion;
        apply_motion_model_kernel<<<numBlocksMotion, threadsPerBlockMotion>>>(arrayX_device, arrayY_device, Nparticles, seed_device);
        CUDA_CHECK(cudaDeviceSynchronize());

        long long error_time = get_time();
        printf("TIME TO SET ERROR TOOK: %f\n", elapsed_time(frame_start_time, error_time));

        // Calculate likelihoods
        // First, calculate indices for each particle
        int threadsPerBlockIndices = 256;
        int numBlocksIndices = (Nparticles + threadsPerBlockIndices - 1) / threadsPerBlockIndices;
        calculate_indices_kernel<<<numBlocksIndices, threadsPerBlockIndices>>>(ind_device, arrayX_device, arrayY_device, objxy_device, countOnes, Nparticles, k, IszY, Nfr, max_size);
        CUDA_CHECK(cudaDeviceSynchronize());

        // Then, calculate likelihood sum for each particle
        for (int p = 0; p < Nparticles; ++p) {
            likelihood_device[p] = 0.0; // Reset likelihood for the particle
            int threadsPerBlockLikelihood = 256;
            int numBlocksLikelihood = (countOnes + threadsPerBlockLikelihood - 1) / threadsPerBlockLikelihood;
            calcLikelihoodSum_kernel<<<numBlocksLikelihood, threadsPerBlockLikelihood>>>(I_device, ind_device, countOnes, likelihood_device, p, Nparticles, countOnes, k, IszY, Nfr, max_size);
            CUDA_CHECK(cudaDeviceSynchronize());
            // Normalize likelihood sum by countOnes
            if (countOnes > 0) {
                likelihood_device[p] /= (double)countOnes;
            }
        }

        long long likelihood_time = get_time();
        printf("TIME TO GET LIKELIHOODS TOOK: %f\n", elapsed_time(error_time, likelihood_time));

        // Update weights
        int threadsPerBlockUpdate = 256;
        int numBlocksUpdate = (Nparticles + threadsPerBlockUpdate - 1) / threadsPerBlockUpdate;
        update_weights_kernel<<<numBlocksUpdate, threadsPerBlockUpdate>>>(weights_device, likelihood_device, Nparticles);
        CUDA_CHECK(cudaDeviceSynchronize());

        long long exponential_time = get_time();
        printf("TIME TO GET EXP TOOK: %f\n", elapsed_time(likelihood_time, exponential_time));

        // Sum weights
        double sumWeights_host = 0;
        for (int i = 0; i < Nparticles; ++i) {
            sumWeights_host += weights_device[i];
        }
        long long sum_time = get_time();
        printf("TIME TO SUM WEIGHTS TOOK: %f\n", elapsed_time(exponential_time, sum_time));

        // Normalize weights
        normalize_weights_kernel<<<numBlocksUpdate, threadsPerBlockUpdate>>>(weights_device, sumWeights_host, Nparticles);
        CUDA_CHECK(cudaDeviceSynchronize());

        long long normalize_time = get_time();
        printf("TIME TO NORMALIZE WEIGHTS TOOK: %f\n", elapsed_time(sum_time, normalize_time));

        // Estimate object location
        double xe_device_val = 0.0;
        double ye_device_val = 0.0;
        CUDA_CHECK(cudaMalloc(&xe_device_val, sizeof(double)));
        CUDA_CHECK(cudaMalloc(&ye_device_val, sizeof(double)));
        CUDA_CHECK(cudaMemset(xe_device_val, 0, sizeof(double)));
        CUDA_CHECK(cudaMemset(ye_device_val, 0, sizeof(double)));

        estimate_object_location_kernel<<<1, 1>>>(xe_device_val, ye_device_val, arrayX_device, arrayY_device, weights_device, Nparticles);
        CUDA_CHECK(cudaDeviceSynchronize());

        CUDA_CHECK(cudaMemcpy(&xe_host, xe_device_val, sizeof(double), cudaMemcpyDeviceToHost));
        CUDA_CHECK(cudaMemcpy(&ye_host, ye_device_val, sizeof(double), cudaMemcpyDeviceToHost));

        printf("XE: %lf\n", xe_host);
        printf("YE: %lf\n", ye_host);
        double distance = sqrt(pow((double)(xe_host - roundDouble_device(IszY / 2.0)), 2) + pow((double)(ye_host - roundDouble_device(IszX / 2.0)), 2));
        printf("%lf\n", distance);

        CUDA_CHECK(cudaFree(xe_device_val));
        CUDA_CHECK(cudaFree(ye_device_val));

        long long move_time = get_time();
        printf("TIME TO MOVE OBJECT TOOK: %f\n", elapsed_time(normalize_time, move_time));

        // Resampling
        // Calculate CDF
        calculate_CDF_kernel<<<numBlocksUpdate, threadsPerBlockUpdate>>>(weights_device, CDF_device, Nparticles);
        CUDA_CHECK(cudaDeviceSynchronize());

        long long cum_sum_time = get_time();
        printf("TIME TO CALC CUM SUM TOOK: %f\n", elapsed_time(move_time, cum_sum_time));

        // Calculate u
        double u1_host = (1.0 / (double)Nparticles) * randu_device(seed_device, 0); // Use randu_device on device
        calculate_u_kernel<<<numBlocksUpdate, threadsPerBlockUpdate>>>(u_device, u1_host, Nparticles);
        CUDA_CHECK(cudaDeviceSynchronize());

        long long u_time = get_time();
