#define CUDA_CHECK(err) checkCudaErrors(err, __FILE__, __LINE__)

// --- Device-side Utility Functions ---
__device__ double roundDouble_device(double value) {
    return round(value);
}

__device__ double randu_device(unsigned int *seed, unsigned int index) {
    unsigned int num = 1103515245 * seed[index] + 12345;
    seed[index] = num % 2147483647; // Using INT_MAX as modulus
    return fabs((double)seed[index] / 2147483647.0);
}

__device__ double randn_device(unsigned int *seed, unsigned int index) {
    double u = randu_device(seed, index);
    double v = randu_device(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
