int main(int argc, char *argv[]) {
    char *usage = "openmp.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>";
    if (argc != 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect\n");
        return 0;
    }
    if (IszX <= 0) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect\n");
        return 0;
    }
    if (IszY <= 0) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect\n");
        return 0;
    }
    if (Nfr <= 0) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect\n");
        return 0;
    }
    if (Nparticles <= 0) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    // Allocate host memory
    int *I_host = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    unsigned int *seed_host = (unsigned int *)malloc(sizeof(unsigned int) * Nparticles);

    // Initialize seed
    for (int i = 0; i < Nparticles; ++i) {
        seed_host[i] = (unsigned int)time(0) * (i + 1); // Ensure different seeds
    }

    long long start_time = get_time();

    // --- Simulate videoSequence on host and then copy to device ---
    int max_size_host = IszX * IszY * Nfr;
    for (int i = 0; i < max_size_host; ++i) I_host[i] = 0; // Initialize to 0

    int x0_host = IszY / 2;
    int y0_host = IszX / 2;

    // Initial point
    I_host[x0_host * IszY * Nfr + y0_host * Nfr + 0] = 1;

    // Move point
    for (int k = 1; k < Nfr; k++) {
        int xk_host = abs(x0_host + (k - 1));
        int yk_host = abs(y0_host - 2 * (k - 1));
        int pos_host = yk_host * IszY * Nfr + xk_host * Nfr + k;
        if (pos_host < max_size_host) {
            I_host[pos_host] = 1;
        }
    }

    // Dilate matrix (using host-side functions for simplicity)
    int *newMatrix_host = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    for (int i = 0; i < IszX * IszY * Nfr; ++i) newMatrix_host[i] = 0;

    int radius_dilate = 5;
    for (int z = 0; z < Nfr; z++) {
        for (int x = 0; x < IszX; x++) {
            for (int y = 0; y < IszY; y++) {
                if (I_host[x * IszY * Nfr + y * Nfr + z] == 1) {
                    // Dilate_matrix (host-side)
                    int startX = max(0, x - radius_dilate);
                    int startY = max(0, y - radius_dilate);
                    int endX = min(IszX, x + radius_dilate);
                    int endY = min(IszY, y + radius_dilate);

                    for (int cur_x = startX; cur_x < endX; ++cur_x) {
                        for (int cur_y = startY; cur_y < endY; ++cur_y) {
                            double distance = sqrt(pow((double)(cur_x - x), 2) + pow((double)(cur_y - y), 2));
                            if (distance < radius_dilate) {
                                newMatrix_host[cur_x * IszY * Nfr + cur_y * Nfr + z] = 1;
                            }
                        }
                    }
                }
            }
        }
    }
    memcpy(I_host, newMatrix_host, sizeof(int) * IszX * IszY * Nfr);
    free(newMatrix_host);

    // Define background, add noise (using host-side functions)
    // setIf
    int testValue = 0, newValue = 100;
    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int z = 0; z < Nfr; z++) {
                if (I_host[x * IszY * Nfr + y * Nfr + z] == testValue)
                    I_host[x * IszY * Nfr + y * Nfr + z] = newValue;
            }
        }
    }
    testValue = 1, newValue = 228;
    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int z = 0; z < Nfr; z++) {
                if (I_host[x * IszY * Nfr + y * Nfr + z] == testValue)
                    I_host[x * IszY * Nfr + y * Nfr + z] = newValue;
            }
        }
    }

    // addNoise
    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int z = 0; z < Nfr; z++) {
                I_host[x * IszY * Nfr + y * Nfr + z] = I_host[x * IszY * Nfr + y * Nfr + z] + (int)(5 * randn_device(seed_host, 0)); // Using host seed for now
            }
        }
    }

    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start_time, endVideoSequence));

    // Call particle filter on CUDA device
    particleFilter(I_host, IszX, IszY, Nfr, seed_host, Nparticles);

    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start_time, endParticleFilter));

    free(I_host);
    free(seed_host);

    return 0;
}

