    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src_h, *dst_h, *temp_h;
    int *src_d, *dst_d, *wall_d;
    int min;

    dst_h = result;
    src_h = new int[cols];

    // Allocate memory on the device
    cudaMalloc(&src_d, cols * sizeof(int));
    cudaMalloc(&dst_d, cols * sizeof(int));
    cudaMalloc(&wall_d, rows * cols * sizeof(int));

    // Copy initial wall data to device
    cudaMemcpy(wall_d, data, rows * cols * sizeof(int), cudaMemcpyHostToDevice);

    pin_stats_reset();

    // Copy initial result (row 0) to src_d
    cudaMemcpy(src_d, dst_h, cols * sizeof(int), cudaMemcpyHostToDevice);

    int block_size = 256;
    dim3 grid_size((cols + block_size - 1) / block_size);

    for (int t = 0; t < rows - 1; t++) {
        temp_h = src_h;
        src_h = dst_h;
        dst_h = temp_h;

        // Swap device pointers for src and dst
        int* temp_d = src_d;
        src_d = dst_d;
        dst_d = temp_d;

        // Launch the CUDA kernel
        pathfinder_kernel<<<grid_size, block_size>>>(src_d, dst_d, wall_d, cols, t + 1);
        cudaDeviceSynchronize(); // Ensure kernel completion
    }

    // Copy the final result back to host
    cudaMemcpy(dst_h, dst_d, cols * sizeof(int), cudaMemcpyDeviceToHost);

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

#ifdef BENCH_PRINT

    // Original code printed data[i] which is the flattened wall.
