    printf("\n") ;

#endif

    // Free device memory
    cudaFree(src_d);
    cudaFree(dst_d);
    cudaFree(wall_d);

    delete [] data;
    delete [] wall;
    delete [] dst_h;
    delete [] src_h;
}

